INSERT INTO websites (name, slug, url, logo_url, short_description, long_description, category, tags, pricing_model, language, is_featured, is_active, click_count) VALUES
('Lex', 'lex', 'https://lex.page', '', 'Yapay zeka destekli, modern bir yazı editörü. Fikirlerinizi hızla taslağa dönüştürün.', 'Lex is an AI-powered word processor that helps you write faster and better.', 'Productivity', '["writing", "editor", "ai"]', 'freemium', 'tr', 1, 1, 12400),
