('Canva', 'canva', 'https://canva.com', '', 'Herkesin tasarım yapabilmesini sağlayan, AI araçlarıyla güçlendirilmiş platform.', 'Canva is a free-to-use online graphic design tool.', 'Design', '["design", "graphics", "easy"]', 'freemium', 'tr', 0, 1, 120000),
('Notion', 'notion', 'https://notion.so', '', 'AI entegrasyonu ile not alma, proje yönetimi ve işbirliği platformu.', 'Notion is a single space where you can think, write, and plan.', 'Productivity', '["notes", "productivity", "all-in-one"]', 'freemium', 'tr', 0, 1, 95000),
('Perplexity', 'perplexity', 'https://perplexity.ai', '', 'Kaynek göstererek cevap veren yapay zeka tabanlı arama motoru.', 'Perplexity AI is an AI-powered conversational search engine.', 'Search', '["search", "ai", "answers"]', 'freemium', 'tr', 0, 1, 40000),
('Gamma', 'gamma', 'https://gamma.app', '', 'Yapay zeka ile saniyeler içinde sunum, döküman ve web sitesi oluşturun.', 'Gamma is a new medium for presenting ideas, powered by AI.', 'Productivity', '["presentation", "ai", "creation"]', 'freemium', 'tr', 0, 1, 25000),
('Tome', 'tome', 'https://tome.app', '', 'AI yardımıyla hikayeleştirme ve sunum hazırlama platformu.', 'Tome is an AI-powered storytelling tool that helps you create compelling narratives.', 'Productivity', '["storytelling", "ai", "slides"]', 'freemium', 'tr', 0, 1, 15000),
('ElevenLabs', 'elevenlabs', 'https://elevenlabs.io', '', 'En gerçekçi AI seslendirme ve metinden sese dönüştürme teknolojisi.', 'ElevenLabs is an American software company developing natural-sounding speech synthesis and text-to-speech software.', 'Audio', '["voice", "ai", "speech"]', 'freemium', 'tr', 0, 1, 35000),
('Suno', 'suno', 'https://suno.com', '', 'Metinden saniyeler içerisinde orijinal müzik ve şarkı üreten yapay zeka.', 'Suno is a generative AI music creation platform.', 'Audio', '["music", "generation", "ai"]', 'freemium', 'tr', 0, 1, 18000),
('Luma', 'luma', 'https://lumalabs.ai', '', 'Muazzam kalitede video üretimi yapan Dream Machine aracı.', 'Luma AI creates high-quality 3D assets and generative video models.', 'Video', '["video", "generation", "3d"]', 'freemium', 'tr', 0, 1, 24000),
('Zapier', 'zapier', 'https://zapier.com', '', 'Uygulamalarınız arasında otomasyon kurarak iş süreçlerinizi hızlandırın.', 'Zapier empowers you to automate your work across 5000+ apps.', 'Utility', '["automation", "integration", "nocode"]', 'freemium', 'tr', 0, 1, 80000),
('Figma', 'figma', 'https://figma.com', '', 'Arayüz tasarımı ve takım işbirliğinde endüstri standardı olan araç.', 'Figma is a collaborative web application for interface design.', 'Design', '["ui", "ux", "design"]', 'freemium', 'tr', 0, 1, 150000),
('Github Copilot', 'copilot', 'https://github.com/features/copilot', '', 'Geliştiriciler için AI kod asistanı, yazılım geliştirme sürecinizi uçurur.', 'GitHub Copilot uses the OpenAI Codex to suggest code and entire functions in real-time.', 'Development', '["coding", "assistant", "ai"]', 'paid', 'tr', 0, 1, 110000);
